const headers = $('Webhook Draft').first().json.headers || {};
const body = $('Webhook Draft').first().json.body || {};
const token = (headers.authorization || headers.Authorization || '').replace('Bearer ', '');
if (!token) return [{json:{error:true,message:'Thiếu token',status:401}}];
let userId;
try { userId = JSON.parse(Buffer.from(token.split('.')[1],'base64').toString()).sub; if(!userId) throw 0; } catch(e) { return [{json:{error:true,message:'Token không hợp lệ',status:401}}]; }
if (!body.protocol_type || !body.equipment_code) return [{json:{error:true,message:'Thiếu protocol_type hoặc equipment_code',status:400}}];
if (!/^[a-z0-9_]{1,30}$/.test(body.protocol_type)) return [{json:{error:true,message:'protocol_type không hợp lệ (chỉ a-z, 0-9, _)',status:400}}];
if (!/^[A-Za-z0-9\-_\.]{1,50}$/.test(body.equipment_code)) return [{json:{error:true,message:'equipment_code không hợp lệ',status:400}}];
const validLangModes = ['vi','en','vi-en','other'];
const langMode = body.language_mode || 'vi';
if (!validLangModes.includes(langMode)) return [{json:{error:true,message:'language_mode không hợp lệ',status:400}}];
return [{json:{error:false,user_id:userId,protocol_type:body.protocol_type,equipment_code:body.equipment_code,equipment_name:body.equipment_name||'',template_id:body.template_id||null,language_mode:langMode,special_requirements:body.special_requirements||'',manufacturer:body.manufacturer||'',model:body.model||'',location:body.location||'',intended_use:body.intended_use||''}}];

