const results = $input.all().map(i=>i.json);
const prev = $('Parse + Auth').first().json;

// Kiểm tra role
const roles = results.filter(r=>r.role_name).map(r=>r.role_name);
if (!roles.some(r=>['admin','qa_manager','validation'].includes(r))) return [{json:{error:true,message:'Không có quyền viết đề cương',status:403}}];

// Lấy template
const tpl = results.find(r=>r.template_structure);
const eq = results.find(r=>r.equipment_code);
const prompt = results.find(r=>r.prompt_text);

let context = `=== THÔNG TIN THIẾT BỊ ===\nMã: ${prev.equipment_code}\nTên: ${prev.equipment_name || eq?.equipment_name || 'N/A'}\nNSX: ${prev.manufacturer || eq?.manufacturer || 'N/A'}\nModel: ${prev.model || eq?.model || 'N/A'}\nVị trí: ${prev.location || eq?.location || 'N/A'}\nCông dụng: ${prev.intended_use || eq?.intended_use || 'N/A'}\nLoại đề cương: ${prev.protocol_type.toUpperCase()}`;

if (tpl?.template_structure) context += `\n\n=== TEMPLATE CẤU TRÚC ===\n${JSON.stringify(tpl.template_structure, null, 2)}`;
if (prev.special_requirements) context += `\n\n=== YÊU CẦU ĐẶC BIỆT ===\n${prev.special_requirements}`;

const messages = [
  {role:'system',content:prompt?.prompt_text || 'Bạn là GMP Protocol Writer. Viết đề cương bằng tiếng Việt theo template.'},
  {role:'user',content:context + '\n\nHãy viết đề cương ' + prev.protocol_type.toUpperCase() + ' cho thiết bị này theo template. Output bằng tiếng Việt.'}
];

return [{json:{...prev,messages,primary_role:roles[0]}}];

const ai = $input.first().json;
const prev = $('Build AI Request').first().json;
const content = ai.choices?.[0]?.message?.content || 'Không thể tạo đề cương.';

// Save SQL
const escaped = content.replace(/'/g,"''");
const sql = `INSERT INTO generated_protocols (user_id,protocol_type,equipment_code,language_mode,input_data,generated_content,model_used,prompt_version,status) VALUES ('${prev.user_id}'::uuid,'${prev.protocol_type}','${prev.equipment_code}','${prev.language_mode}','${JSON.stringify({equipment_name:prev.equipment_name,manufacturer:prev.manufacturer,model:prev.model}).replace(/'/g,"''")}'::jsonb,'${escaped}','gpt-4o-mini','v1.0','draft') RETURNING id;\nSELECT write_audit_log('${prev.user_id}'::uuid,NULL,'${prev.primary_role}','ai_draft_protocol'::audit_action,'Draft ${prev.protocol_type.toUpperCase()} cho ${prev.equipment_code}');`;

return [{json:{sql,response:{success:true,protocol_type:prev.protocol_type,equipment_code:prev.equipment_code,content,disclaimer:'⚕ [AI-DRAFT] Nội dung do AI tạo, cần người có chuyên môn xem xét và chỉnh sửa trước khi sử dụng.'}}}];
